import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { Subject } from 'rxjs';
import { RuleService } from 'src/app/shared/services/rule.service';

@Component({
  selector: 'npr-rule-translation-summary',
  templateUrl: './rule-translation-summary.component.html',
  styleUrls: ['./rule-translation-summary.component.scss']
})
export class RuleTranslationSummaryComponent implements OnInit {
  translationList: any = [];
  translationDeatils: any;
  dtTrigger: any = new Subject();
  dtOptions: DataTables.Settings = {};

  constructor(private ruleService: RuleService, private router:Router) { }

  ngOnInit(): void {
    this.dtOptions = {
      pagingType: 'full_numbers',
      pageLength : 5,
      columnDefs: [ { type: 'date', 'targets': [5] } ],
      order: [[5, 'desc']],
      processing: true,
      lengthMenu: [[5, 10, 20, -1], [5, 10, 20, 30]],
      // columnDefs: [ { type: 'date', 'targets': [5] } ],
      // order: [[5, 'desc']],

    };
    this.fetchRuleTranslationSummary();
  }

  fetchRuleTranslationSummary() {
    this.ruleService.fetchingruleTranslation()
      .subscribe(resp => {
        console.log(resp);
        this.translationList = resp;
        this.dtTrigger.next();
      })
  }

  onGetId(row) {
    console.log(row);
    this.router.navigate(['/rule-translation/edit', row.transId]);
  }

  ngOnDestroy(): void {
    // Do not forget to unsubscribe the event
    this.dtTrigger.unsubscribe();
  }

  
}
